// Service dùng TimeProvider
public class TokenService(TimeProvider time)
{
    public bool IsExpired(Token token) =>
        time.GetUtcNow() > token.ExpiresAt;

    public async Task WaitForRefreshAsync(CancellationToken ct) =>
        await Task.Delay(TimeSpan.FromSeconds(30), time, ct);
}

// Registration (production)
builder.Services.AddSingleton(TimeProvider.System);

// Test với FakeTimeProvider
// NuGet: Microsoft.Extensions.TimeProvider.Testing
[Fact]
public void Token_IsExpired_WhenPastExpiry()
{
    var fake = new FakeTimeProvider(
        DateTimeOffset.Parse("2026-06-30T00:00:00Z"));
    var svc = new TokenService(fake);
    var token = new Token { ExpiresAt = DateTimeOffset.Parse("2026-06-29T23:59:00Z") };

    Assert.True(svc.IsExpired(token));
}

[Fact]
public async Task WaitForRefresh_CompletesAfterAdvance()
{
    var fake = new FakeTimeProvider();
    var svc = new TokenService(fake);
    var task = svc.WaitForRefreshAsync(CancellationToken.None);

    fake.Advance(TimeSpan.FromSeconds(30)); // advance time
    await task; // completes immediately
}
